import { jsPDF } from 'jspdf';

// Normalize chars not in WinAnsi (ğ→g, ı→i, İ→I)
const tr = (s = '') => String(s)
  .replace(/ğ/g, 'g').replace(/Ğ/g, 'G')
  .replace(/ı/g, 'i').replace(/İ/g, 'I');

const STATUS_ROWS = [
  { key: 'highlight',   label: 'Highlights',                    r: 108, g: 195, b: 108 },
  { key: 'lowlight',    label: 'Lowlights',                     r: 230, g: 160, b:  50 },
  { key: 'waiting',     label: 'Waiting For\nExecutive Support', r:  50, g:  80, b: 160 },
  { key: 'information', label: 'Information',                    r:  40, g: 180, b: 180 },
  { key: 'progress',    label: 'Progress',                      r:  16, g: 185, b: 129 },
];

export function generatePdf({ actions, actionStatuses, userData, weeks, formData }) {
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });

  const pageW  = 210;
  const pageH  = 297;
  const mL     = 15;   // left margin
  const mR     = 15;   // right margin
  const cW     = pageW - mL - mR; // 180 mm content width

  // ─── HEADER ────────────────────────────────────────────────────────────────
  const hY   = 15;
  const hH   = 24;
  const tealW = cW * 0.62;  // ~112 mm teal block

  // Teal rectangle
  doc.setFillColor(72, 199, 199);
  doc.rect(mL, hY, tealW, hH, 'F');

  // Title inside teal
  doc.setTextColor(255, 255, 255);
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(13);
  doc.text('Haftalik Rapor', mL + 5, hY + 9);

  // Week label inside teal
  const weekObj  = weeks.find(w => String(w.WeekNumber) === String(formData.week));
  const weekLabel = weekObj ? `${weekObj.WeekNumber}. Hafta  ${weekObj.Year}` : '';
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(8);
  doc.text(weekLabel, mL + 5, hY + 17);

  // Right side of header (outside teal)
  const rX = mL + tealW + 6;
  doc.setTextColor(40, 40, 40);
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(10);
  doc.text(tr(userData.FullName || ''), rX, hY + 9);
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(8);
  doc.text(tr(userData.DepartmentName || ''), rX, hY + 16);

  // Thin border around entire header row
  doc.setDrawColor(180, 180, 180);
  doc.setLineWidth(0.3);
  doc.rect(mL, hY, cW, hH);
  doc.line(mL + tealW, hY, mL + tealW, hY + hH); // vertical split

  // ─── TABLE ─────────────────────────────────────────────────────────────────
  const leftCW  = 45;   // left icon column width
  const rightCW = cW - leftCW;
  const minH    = 32;   // minimum row height mm
  const padX    = 4;
  const padY    = 4;

  let curY = hY + hH;

  for (const row of STATUS_ROWS) {
    // Collect status-matching actions (excluding images)
    const matched = actions.filter(a => actionStatuses[a.id] === row.key);
    if (matched.length === 0) continue;

    // Build bullet lines for right cell
    const bullets = [];
    matched.forEach(a => {
      (a.actionItems || [])
        .filter(i => i.type === 'text' && i.value && i.value.trim())
        .forEach(i => bullets.push('• ' + tr(i.value.trim())));
    });

    // Measure wrapped text height
    doc.setFontSize(9);
    const maxTextW = rightCW - padX * 2;
    const allWrapped = [];
    bullets.forEach(b => {
      const wrapped = doc.splitTextToSize(b, maxTextW);
      allWrapped.push(...wrapped);
    });
    const lineH = 5;
    const textBlockH = allWrapped.length * lineH;
    const rowH = Math.max(minH, textBlockH + padY * 2 + 4);

    // Page break check
    if (curY + rowH > pageH - 15) {
      doc.addPage();
      curY = 15;
    }

    // Row background (alternating subtle)
    doc.setFillColor(251, 252, 255);
    doc.rect(mL, curY, cW, rowH, 'F');

    // Row border
    doc.setDrawColor(200, 210, 220);
    doc.setLineWidth(0.3);
    doc.rect(mL, curY, cW, rowH);
    doc.line(mL + leftCW, curY, mL + leftCW, curY + rowH);

    // Colored circle in left cell
    const cx = mL + leftCW / 2;
    const cy = curY + rowH / 2 - 5;
    const cr = 9;
    doc.setFillColor(row.r, row.g, row.b);
    doc.circle(cx, cy, cr, 'F');

    // Status label below circle
    doc.setTextColor(60, 60, 60);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(7);
    const labelParts = row.label.split('\n');
    labelParts.forEach((part, i) => {
      doc.text(part, cx, cy + cr + 4 + i * 4, { align: 'center' });
    });

    // Action texts in right cell
    doc.setTextColor(30, 30, 30);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(9);
    doc.text(allWrapped, mL + leftCW + padX, curY + padY + 5);

    curY += rowH;
  }

  // Bottom border line
  doc.setDrawColor(180, 180, 180);
  doc.setLineWidth(0.4);
  doc.line(mL, curY, mL + cW, curY);

  // ─── FOOTER ────────────────────────────────────────────────────────────────
  doc.setFont('helvetica', 'italic');
  doc.setFontSize(7);
  doc.setTextColor(160, 160, 160);
  const today = new Date().toLocaleDateString('tr-TR');
  doc.text(`Olusturulma tarihi: ${today}`, mL, pageH - 8);
  doc.text(tr(userData.FullName || ''), pageW - mR, pageH - 8, { align: 'right' });

  // Save
  const name = `Haftalik_Rapor_H${formData.week || 'X'}.pdf`;
  doc.save(name);
}
